define('local_course_carousel/carousel',[],function(){return{init:function(){var carousel=document.querySelector('#carouselExampleAutoplaying');if(!carousel){return}var carouselInner=carousel.querySelector('.carousel-inner');var prevButton=carousel.querySelector('.carousel-control-prev');var nextButton=carousel.querySelector('.carousel-control-next');if(!carouselInner||!prevButton||!nextButton){return}var cards=Array.prototype.slice.call(carouselInner.querySelectorAll('.card'));if(cards.length===0){return}var uniqueCards=cards.filter(function(card,index,list){var image=card.querySelector('img');var imageSrc=image?image.getAttribute('src'):'';return list.findIndex(function(item){var itemImage=item.querySelector('img');return(itemImage?itemImage.getAttribute('src'):'')===imageSrc})===index});var visibleCards=3;var slideDelay=3000;var currentIndex=0;var autoSlide;carouselInner.innerHTML='';var cardWrapper=document.createElement('div');cardWrapper.className='card-wraper';uniqueCards.forEach(function(card){cardWrapper.appendChild(card.cloneNode(true))});uniqueCards.slice(0,visibleCards).forEach(function(card){cardWrapper.appendChild(card.cloneNode(true))});carouselInner.appendChild(cardWrapper);var moveSlider=function(){var firstCard=cardWrapper.querySelector('.card');if(!firstCard){return}var cardWidth=firstCard.offsetWidth;var gap=parseFloat(getComputedStyle(cardWrapper).gap)||0;cardWrapper.style.transform='translateX(-'+currentIndex*(cardWidth+gap)+'px)'};var nextSlide=function(){currentIndex++;cardWrapper.style.transition='transform .5s ease';moveSlider()};var prevSlide=function(){if(currentIndex===0){currentIndex=uniqueCards.length;cardWrapper.style.transition='none';moveSlider()}requestAnimationFrame(function(){currentIndex--;cardWrapper.style.transition='transform .5s ease';moveSlider()})};var startAutoSlide=function(){autoSlide=setInterval(nextSlide,slideDelay)};var resetAutoSlide=function(){clearInterval(autoSlide);startAutoSlide()};nextButton.addEventListener('click',function(){nextSlide();resetAutoSlide()});prevButton.addEventListener('click',function(){prevSlide();resetAutoSlide()});cardWrapper.addEventListener('transitionend',function(){if(currentIndex===uniqueCards.length){currentIndex=0;cardWrapper.style.transition='none';moveSlider()}});window.addEventListener('resize',moveSlider);startAutoSlide()}}});